23→/// Run database migrations for the sessions crate.
24→///
25→/// This creates the `sessions` and `channel_sessions` tables. Should be called
26→/// at application startup after [`moltis_projects::run_migrations`] (sessions
27→/// has a foreign key to projects).
28→pub async fn run_migrations(pool: &sqlx::SqlitePool) -> Result<()> {
29→    sqlx::migrate!("./migrations")
30→        .set_ignore_missing(true)
31→        .run(pool)
32→        .await?;
33→    Ok(())
34→}
