 22→/// Default (deterministic) session key for a channel chat.
 23→///
 24→/// For Telegram forum topics the thread ID is appended so each topic gets its
 25→/// own session: `telegram:bot:chat:thread`.
 26→fn default_channel_session_key(target: &ChannelReplyTarget) -> String {
 27→    match &target.thread_id {
 28→        Some(tid) => format!(
 29→            "{}:{}:{}:{}",
 30→            target.channel_type, target.account_id, target.chat_id, tid
 31→        ),
 32→        None => format!(
 33→            "{}:{}:{}",
 34→            target.channel_type, target.account_id, target.chat_id
 35→        ),
 36→    }
 37→}
 38→
 39→/// Resolve the active session key for a channel chat.
 40→/// Uses the forward mapping table if an override exists, otherwise falls back
 41→/// to the deterministic key.
 42→async fn resolve_channel_session(
 43→    target: &ChannelReplyTarget,
 44→    metadata: &SqliteSessionMetadata,
 45→) -> String {
 46→    if let Some(key) = metadata
 47→        .get_active_session(
 48→            target.channel_type.as_str(),
 49→            &target.account_id,
 50→            &target.chat_id,
 51→            target.thread_id.as_deref(),
 52→        )
 53→        .await
 54→    {
 55→        return key;
 56→    }
 57→    default_channel_session_key(target)
 58→}
