1175→    async fn patch(&self, params: Value) -> ServiceResult {
1176→        let p: PatchParams = parse_params(params)?;
1177→        let key = &p.key;
1178→
1179→        let entry = self
1180→            .metadata
1181→            .get(key)
1182→            .await
1183→            .ok_or_else(|| format!("session '{key}' not found"))?;
1184→        if p.label.is_some() {
1185→            if entry.channel_binding.is_some() {
1186→                return Err("cannot rename a channel-bound session".into());
1187→            }
1188→            let _ = self.metadata.upsert(key, p.label).await;
1189→        }
1190→        if p.model.is_some() {
1191→            self.metadata.set_model(key, p.model).await;
1192→        }
1193→        if let Some(project_id_opt) = p.project_id {
1194→            let project_id = project_id_opt.filter(|s| !s.is_empty());
1195→            self.metadata.set_project_id(key, project_id).await;
1196→        }
1197→        if let Some(worktree_branch_opt) = p.worktree_branch {
1198→            let worktree_branch = worktree_branch_opt.filter(|s| !s.is_empty());
1199→            self.metadata
1200→                .set_worktree_branch(key, worktree_branch)
1201→                .await;
