 31→function buildShareUrl(payload) {
 32→	var url = `${window.location.origin}${payload.path}`;
 33→	if (payload.accessKey) {
 34→		url += `?k=${encodeURIComponent(payload.accessKey)}`;
 35→	}
 36→	return url;
 37→}
