 88→	var [stopping, setStopping] = useState(false);
 89→	var [switchingAgent, setSwitchingAgent] = useState(false);
 90→	var [agentOptions, setAgentOptions] = useState(initialAgentOptions);
 91→	var [defaultAgentId, setDefaultAgentId] = useState(initialDefaultAgentId);
 92→	var [agentOptionsLoaded, setAgentOptionsLoaded] = useState(initialAgentOptions.length > 0);
 93→	var [nodeOptions, setNodeOptions] = useState([]);
 94→	var [switchingNode, setSwitchingNode] = useState(false);
 95→	var inputRef = useRef(null);
 96→
 97→	var fullName = session ? session.label || session.key : currentKey;
 98→	var displayName = nameOwnLine ? fullName : fullName.length > 20 ? `${fullName.slice(0, 20)}\u2026` : fullName;
 99→	var replying = session?.replying.value;
100→	var activeRunId = session?.activeRunId.value || null;
101→
102→	var isMain = currentKey === "main";
103→	var isChannel = session?.channelBinding || currentKey.startsWith("telegram:") || currentKey.startsWith("msteams:");
104→	var isCron = currentKey.startsWith("cron:");
105→	var canRename = !(isMain || isChannel || isCron);
106→	var canStop = !isCron && replying;
107→	var currentAgentId = session?.agent_id || defaultAgentId || "main";
108→	var currentNodeId = session?.node_id || "";
109→
110→	useEffect(() => {
111→		var cancelled = false;
112→		sendRpc("agents.list", {}).then((res) => {
113→			if (cancelled) return;
114→			if (!res?.ok) {
115→				setAgentOptionsLoaded(true);
116→				return;
117→			}
118→			var parsed = parseAgentsListPayload(res.payload);
119→			setDefaultAgentId(parsed.defaultId);
120→			setAgentOptions(parsed.agents);
121→			setAgentOptionsLoaded(true);
122→		});
123→		return () => {
124→			cancelled = true;
125→		};
126→	}, [currentKey]);
127→
128→	// Fetch connected nodes and subscribe to presence updates.
129→	useEffect(() => {
130→		var cancelled = false;
131→		var fetchNodes = () => {
132→			sendRpc("node.list", {}).then((res) => {
133→				if (cancelled || !res?.ok) return;
134→				setNodeOptions(Array.isArray(res.payload) ? res.payload : []);
135→			});
136→		};
137→		fetchNodes();
138→		var unsub = onEvent("presence", () => {
