55→/// Filter out empty assistant messages from history before sending to the UI.
56→///
57→/// Empty assistant messages are persisted in the session JSONL for LLM history
58→/// coherence (so the model sees a complete user→assistant turn), but they
59→/// should not be shown in the web UI or sent to channels.
60→fn filter_ui_history(messages: Vec<Value>) -> Vec<Value> {
61→    messages
62→        .into_iter()
63→        .enumerate()
64→        .filter_map(|(idx, mut msg)| {
65→            if msg.get("role").and_then(|v| v.as_str()) == Some("assistant") {
66→                let has_content = msg
67→                    .get("content")
68→                    .and_then(|v| v.as_str())
69→                    .is_some_and(|s| !s.trim().is_empty());
70→                let has_reasoning = msg
71→                    .get("reasoning")
72→                    .and_then(|v| v.as_str())
73→                    .is_some_and(|s| !s.trim().is_empty());
74→                let has_audio = msg
75→                    .get("audio")
76→                    .and_then(|v| v.as_str())
77→                    .is_some_and(|s| !s.trim().is_empty());
78→                let keep = has_content || has_reasoning || has_audio;
79→                if !keep {
80→                    return None;
81→                }
82→            }
83→            if let Some(obj) = msg.as_object_mut() {
84→                obj.insert("historyIndex".to_string(), serde_json::json!(idx));
85→            }
86→            Some(msg)
87→        })
88→        .collect()
89→}
