 71→fn parse_coordinate_component(input: &str) -> Option<f64> {
 72→    let trimmed = input
 73→        .trim()
 74→        .trim_matches(|c| matches!(c, '(' | ')' | '[' | ']' | '{' | '}'));
 75→    if trimmed.is_empty() {
 76→        return None;
 77→    }
 78→
 79→    let mut end = 0usize;
 80→    for (idx, ch) in trimmed.char_indices() {
 81→        if ch.is_ascii_digit() || matches!(ch, '+' | '-' | '.') {
 82→            end = idx + ch.len_utf8();
 83→        } else {
 84→            break;
 85→        }
 86→    }
 87→    if end == 0 {
 88→        return None;
 89→    }
 90→    let token = &trimmed[..end];
 91→    if !token.chars().any(|c| c.is_ascii_digit()) {
 92→        return None;
 93→    }
 94→    token.parse::<f64>().ok()
 95→}
