 12→function isRetryableRpcError(message) {
 13→	if (typeof message !== "string") return false;
 14→	return message.includes("WebSocket not connected") || message.includes("WebSocket disconnected");
 15→}
 16→
 17→async function sendRpcFromPage(page, method, params) {
 18→	let lastResponse = null;
 19→	for (let attempt = 0; attempt < 40; attempt++) {
 20→		if (attempt > 0) {
 21→			await waitForWsConnected(page);
 22→		}
 23→		lastResponse = await page
 24→			.evaluate(
 25→				async ({ methodName, methodParams }) => {
 26→					var appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
 27→					if (!appScript) throw new Error("app module script not found");
 28→					var appUrl = new URL(appScript.src, window.location.origin);
 29→					var prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
 30→					var helpers = await import(`${prefix}js/helpers.js`);
 31→					return helpers.sendRpc(methodName, methodParams);
 32→				},
 33→				{
 34→					methodName: method,
 35→					methodParams: params,
 36→				},
 37→			)
 38→			.catch((error) => ({ ok: false, error: { message: error?.message || String(error) } }));
 39→
 40→		if (lastResponse?.ok) return lastResponse;
 41→		if (!isRetryableRpcError(lastResponse?.error?.message)) return lastResponse;
 42→	}
 43→	return lastResponse;
 44→}
 45→
 46→async function expectRpcOk(page, method, params) {
 47→	const response = await sendRpcFromPage(page, method, params);
 48→	expect(response?.ok, `RPC ${method} failed: ${response?.error?.message || "unknown error"}`).toBeTruthy();
 49→	return response;
 50→}
