 52→async function setSwitchRpcSendMode(page, mode, delayMs = 0) {
 53→	await page.evaluate(
 54→		async ({ desiredMode, desiredDelayMs }) => {
 55→			const appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
 56→			if (!appScript) throw new Error("app module script not found");
 57→			const appUrl = new URL(appScript.src, window.location.origin);
 58→			const prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
 59→			const stateModule = await import(`${prefix}js/state.js`);
 60→			const ws = stateModule.ws;
 61→			if (!ws) throw new Error("websocket unavailable");
 62→
 63→			if (!window.__origSwitchWsSend) {
 64→				window.__origSwitchWsSend = ws.send.bind(ws);
 65→			}
 66→			if (desiredMode === "restore") {
 67→				ws.send = window.__origSwitchWsSend;
 68→				return;
 69→			}
 70→
 71→			ws.send = (payload) => {
 72→				try {
 73→					const parsed = JSON.parse(payload);
 74→					if (parsed?.method === "sessions.switch") {
 75→						if (desiredMode === "drop") return;
 76→						if (desiredMode === "delay") {
 77→							setTimeout(() => window.__origSwitchWsSend(payload), desiredDelayMs);
 78→							return;
 79→						}
 80→					}
 81→				} catch (_err) {
 82→					// Fall through to the original sender.
 83→				}
 84→				return window.__origSwitchWsSend(payload);
 85→			};
 86→		},
 87→		{ desiredMode: mode, desiredDelayMs: delayMs },
 88→	);
 89→}
